def is_prime(n):
    if n < 2:
        return False
    if n % 2 == 0:
        return n == 2
    i = 3
    while i * i <= n:
        if n % i == 0:
            return False
        i += 2
    return True

primes = []
candidate = 2
while len(primes) < 1000:
    if is_prime(candidate):
        primes.append(candidate)
    candidate += 1

result = ', '.join(str(p) for p in primes)
print(result[:5000])

def primes_n(n):
    primes = []
    candidate = 2
    while len(primes) < n:
        is_prime = True
        if candidate % 2 == 0 and candidate != 2:
            is_prime = False
        else:
            i = 3
            max_i = int(candidate**0.5) + 1
            while i <= max_i:
                if candidate % i == 0:
                    is_prime = False
                    break
                i += 2
        if is_prime:
            primes.append(candidate)
        candidate += 1
    return primes

first_100 = primes_n(100)
print(', '.join(map(str, first_100)))
